                                    uint32_t coBase, uint32_t curCO)
    {
        AscendC::LocalTensor<float> yLocal = yQueue_.DeQue<float>();
        for (uint32_t co = 0; co < curCO; ++co) {
            const uint32_t gmOffset = OffsetY(nIdx, coBase + co, hIdx, wStart);
            AscendC::DataCopy(yGm_[gmOffset], yLocal[co * tileW_], curW);
        }
        yQueue_.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> xQueue_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> wQueue_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> yQueue_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> wGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t n_{0}, cIn_{0}, h_{0}, w_{0}, cOut_{0};
    uint32_t tileW_{0}, tileCO_{0};
};

