    const uint32_t N    = static_cast<uint32_t>(x_shape->GetDim(0));
    const uint32_t Cin  = static_cast<uint32_t>(x_shape->GetDim(1));
    const uint32_t H    = static_cast<uint32_t>(x_shape->GetDim(2));
    const uint32_t W    = static_cast<uint32_t>(x_shape->GetDim(3));
    const uint32_t Cout = static_cast<uint32_t>(w_shape->GetDim(0));
    // const uint32_t CinW = static_cast<uint32_t>(w_shape->GetDim(1)); // assumed equal to Cin

    // Choose tileCO and tileW under UB budget.
    uint32_t tileCO = std::min<uint32_t>(Cout, MAX_TILE_CO);
    uint32_t tileW = std::min<uint32_t>(W, MAX_TILE_W);
    tileW = AlignDown(tileW, ALIGN_W);
    if (tileW == 0) tileW = std::min<uint32_t>(W, ALIGN_W);

    bool found = false;
    for (; tileCO >= MIN_TILE_CO && !found; tileCO = (tileCO > MIN_TILE_CO ? AlignDown(tileCO - 1, 1) : 0)) {
