            continue;
        }
        tileW = std::min<uint32_t>(W, std::min<uint32_t>(MAX_TILE_W, maxTileWByBudget));
        tileW = AlignDown(tileW, ALIGN_W);
        if (tileW >= MIN_TILE_W) {
            found = true;
            break;
        }
    }

    if (!found) {
        // Fallback tiny tiles if extremely constrained
        tileCO = std::min<uint32_t>(Cout, MIN_TILE_CO);
        tileW = std::min<uint32_t>(W, ALIGN_W);
        tileW = (tileW == 0) ? W : tileW;
    }

    const uint32_t rows = N * H;
    uint32_t blockDim = rows;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;
    context->SetBlockDim(blockDim);

    tiling.set_n(N);
    tiling.set_cIn(Cin);
    tiling.set_h(H);
    tiling.set_w(W);
    tiling.set_cOut(Cout);
    tiling.set_tileW(tileW);
    tiling.set_tileCO(tileCO);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

