#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 1;

class KernelConvPointwise2dCustom {
public:
    __aicore__ inline KernelConvPointwise2dCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR w, GM_ADDR y,
                                uint32_t n, uint32_t cIn, uint32_t h, uint32_t wDim, uint32_t cOut,
                                uint32_t tileW, uint32_t tileCO)
    {
        n_ = n;
        cIn_ = cIn;
        h_ = h;
        w_ = wDim;
        cOut_ = cOut;
        tileW_ = tileW;
        tileCO_ = tileCO;

        const uint64_t x_elems = static_cast<uint64_t>(n_) * cIn_ * h_ * w_;
        const uint64_t y_elems = static_cast<uint64_t>(n_) * cOut_ * h_ * w_;
        const uint64_t w_elems = static_cast<uint64_t>(cOut_) * cIn_;

        xGm_.SetGlobalBuffer((__gm__ float*)x, x_elems);
        wGm_.SetGlobalBuffer((__gm__ float*)w, w_elems);
        yGm_.SetGlobalBuffer((__gm__ float*)y, y_elems);

        pipe_.InitBuffer(xQueue_, BUFFER_NUM, cIn_ * tileW_ * sizeof(float));
        pipe_.InitBuffer(yQueue_, BUFFER_NUM, tileCO_ * tileW_ * sizeof(float));
        pipe_.InitBuffer(wQueue_, BUFFER_NUM, tileCO_ * cIn_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, tileW_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (n_ == 0 || cIn_ == 0 || h_ == 0 || w_ == 0 || cOut_ == 0) {
            return;
        }

        const uint32_t rows = n_ * h_; // iterate over (n,h)
        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        for (uint32_t r = blockIdx; r < rows; r += blockNum) {
            const uint32_t nIdx = r / h_;
            const uint32_t hIdx = r % h_;

            for (uint32_t coBase = 0; coBase < cOut_; coBase += tileCO_) {
                const uint32_t curCO = (coBase + tileCO_ <= cOut_) ? tileCO_ : (cOut_ - coBase);
                CopyInW(coBase, curCO);

                for (uint32_t wStart = 0; wStart < w_; wStart += tileW_) {
                    const uint32_t curW = (wStart + tileW_ <= w_) ? tileW_ : (w_ - wStart);
                    CopyInX(nIdx, hIdx, wStart, curW);
                    Compute(curW, curCO);
                    CopyOutY(nIdx, hIdx, wStart, curW, coBase, curCO);
                }
            }
        }
    }

private:
    __aicore__ inline uint32_t OffsetX(uint32_t nIdx, uint32_t cIdx, uint32_t hIdx, uint32_t wIdx) const
    {
        // NCHW layout
        return (((nIdx * cIn_ + cIdx) * h_ + hIdx) * w_ + wIdx);
    }

    __aicore__ inline uint32_t OffsetY(uint32_t nIdx, uint32_t cOIdx, uint32_t hIdx, uint32_t wIdx) const
    {
        // NCHW layout for output: [N, COut, H, W]
        return (((nIdx * cOut_ + cOIdx) * h_ + hIdx) * w_ + wIdx);
    }

    __aicore__ inline uint32_t OffsetW(uint32_t cOIdx, uint32_t cIdx) const
    {
        // weight [COut, CIn]
        return (cOIdx * cIn_ + cIdx);
    }

    __aicore__ inline void CopyInW(uint32_t coBase, uint32_t curCO)
    {
        AscendC::LocalTensor<float> wLocal = wQueue_.AllocTensor<float>();
        // Contiguous block: rows [coBase, coBase + curCO), each of length cIn_
        const uint32_t gmOffset = OffsetW(coBase, 0);
        AscendC::DataCopy(wLocal, wGm_[gmOffset], curCO * cIn_);
        wQueue_.EnQue(wLocal);
    }

    __aicore__ inline void CopyInX(uint32_t nIdx, uint32_t hIdx, uint32_t wStart, uint32_t curW)
    {
        AscendC::LocalTensor<float> xLocal = xQueue_.AllocTensor<float>();
        // Pack as rows of length curW for each Cin
        for (uint32_t c = 0; c < cIn_; ++c) {
            const uint32_t gmOffset = OffsetX(nIdx, c, hIdx, wStart);
            AscendC::DataCopy(xLocal[c * tileW_], xGm_[gmOffset], curW);
        }
        xQueue_.EnQue(xLocal);
    }

    __aicore__ inline void Compute(uint32_t curW, uint32_t curCO)
    {
        AscendC::LocalTensor<float> xLocal = xQueue_.DeQue<float>();
        AscendC::LocalTensor<float> wLocal = wQueue_.DeQue<float>();
        AscendC::LocalTensor<float> yLocal = yQueue_.AllocTensor<float>();
        AscendC::LocalTensor<float> tmpLocal = tmpQueue_.AllocTensor<float>();

        // k = 0: initialize y = w[:,0] * x[0,:]
        {
            const uint32_t k = 0;
            AscendC::LocalTensor<float> xRow = xLocal[k * tileW_];
            for (uint32_t co = 0; co < curCO; ++co) {
                const float wVal = wLocal[co * cIn_ + k];
                AscendC::LocalTensor<float> yRow = yLocal[co * tileW_];
                AscendC::Muls(yRow, xRow, wVal, curW);
            }
        }

        // k >= 1: accumulate
        for (uint32_t k = 1; k < cIn_; ++k) {
            AscendC::LocalTensor<float> xRow = xLocal[k * tileW_];
            for (uint32_t co = 0; co < curCO; ++co) {
                const float wVal = wLocal[co * cIn_ + k];
                AscendC::LocalTensor<float> yRow = yLocal[co * tileW_];
                AscendC::Muls(tmpLocal, xRow, wVal, curW);
                AscendC::Add(yRow, yRow, tmpLocal, curW);
            }
        }

        tmpQueue_.FreeTensor(tmpLocal);
        yQueue_.EnQue(yLocal);
        wQueue_.FreeTensor(wLocal);
        xQueue_.FreeTensor(xLocal);
    }

    __aicore__ inline void CopyOutY(uint32_t nIdx, uint32_t hIdx, uint32_t wStart, uint32_t curW,
                                    uint32_t coBase, uint32_t curCO)
    {
        AscendC::LocalTensor<float> yLocal = yQueue_.DeQue<float>();
        for (uint32_t co = 0; co < curCO; ++co) {
            const uint32_t gmOffset = OffsetY(nIdx, coBase + co, hIdx, wStart);
            AscendC::DataCopy(yGm_[gmOffset], yLocal[co * tileW_], curW);
        }
        yQueue_.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> xQueue_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> wQueue_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> yQueue_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> wGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t n_{0}, cIn_{0}, h_{0}, w_{0}, cOut_{0};
    uint32_t tileW_{0}, tileCO_{0};
};

extern "C" __global__ __aicore__ void conv_pointwise_2d_custom(GM_ADDR x, GM_ADDR weight, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelConvPointwise2dCustom op;
    op.Init(x, weight, y,
            tiling_data.n, tiling_data.cIn, tiling_data.h, tiling_data.w, tiling_data.cOut,
            tiling_data.tileW, tiling_data.tileCO);
    op.Process();
}
